import { callMcpSkill } from "@/lib/ai/skills/mcp";

export async function main() {
  const POLYMARKET_ID = "294100e8-c648-4e5f-a254-95a14b56e398";
  const ODDS_API_ID = "43979b21-bce9-4d49-9ddf-d7ad69722056";

  // 1. Browse Polymarket sports category
  const browseResult = await callMcpSkill({
    toolId: POLYMARKET_ID,
    toolName: "browse_category",
    args: {
      category: "sports",
      sortBy: "volume",
      limit: 1
    }
  });

  const topMarket = browseResult.events?.[0];

  if (!topMarket) {
    return { error: "No sports markets found." };
  }

  // 2. Get detailed outcome data for the 2026 NBA Champion market
  const outcomesResult = await callMcpSkill({
    toolId: POLYMARKET_ID,
    toolName: "get_event_outcomes",
    args: {
      slug: topMarket.slug,
      sortBy: "price"
    }
  });

  // 3. Fetch Sports Betting Odds for cross-reference (NBA Outrights)
  // We use find_best_odds since we are comparing winner markets
  const oddsResult = await callMcpSkill({
    toolId: ODDS_API_ID,
    toolName: "find_best_odds",
    args: {
      sport: "basketball_nba_championship_winner",
      market: "outrights"
    }
  });

  // 4. Analyze pricing efficiency (The original code missed that this returns an object with a 'marketEfficiency' key)
  const efficiencyResult = await callMcpSkill({
    toolId: POLYMARKET_ID,
    toolName: "check_market_efficiency",
    args: {
      slug: topMarket.slug
    }
  });

  // 5. Cross-reference: Compare Polymarket Probabilities vs Bookmaker Implied Probabilities
  const polymarketOutcomes = outcomesResult.outcomes || [];
  const sportsbookEvents = oddsResult.events || [];

  // Find the matching championship event in the Odds API results
  const nbaChampionship = sportsbookEvents.find(e => 
    e.event.toLowerCase().includes("nba") && e.event.toLowerCase().includes("championship")
  ) || sportsbookEvents[0];

  const comparisons = polymarketOutcomes.slice(0, 5).map(polyOutcome => {
    const sportsBookOutcome = nbaChampionship?.outcomes?.find(so => 
      so.name.toLowerCase().includes(polyOutcome.name.toLowerCase()) || 
      polyOutcome.name.toLowerCase().includes(so.name.toLowerCase())
    );

    const polyProb = polyOutcome.price;
    // Implied prob from decimal odds: 1/odds
    const sportsProb = sportsBookOutcome ? (1 / sportsBookOutcome.bestOdds) : null;
    const gap = (sportsProb !== null) ? (polyProb - sportsProb) : null;

    return {
      team: polyOutcome.name,
      polymarketProb: polyProb,
      sportsbookProb: sportsProb ? parseFloat(sportsProb.toFixed(4)) : "N/A",
      gap: gap ? parseFloat(gap.toFixed(4)) : "N/A",
      recommendation: gap && gap > 0.05 ? "Polymarket Overvalued" : gap && gap < -0.05 ? "Value on Polymarket" : "Efficient"
    };
  });

  return {
    marketInfo: {
      title: topMarket.title,
      slug: topMarket.slug,
      volume: topMarket.volume
    },
    efficiency: {
      vig: efficiencyResult.marketEfficiency?.vig,
      recommendation: efficiencyResult.recommendation
    },
    crossReference: comparisons,
    rawOutcomes: polymarketOutcomes.slice(0, 10).map(o => ({
      name: o.name,
      price: o.price,
      volume: o.volume
    })),
    fetchedAt: new Date().toISOString()
  };
}
